int main(void){ sda_config c; if(sda_config_builtin("frodo1344",&c)) return 1; sda_generation_result r; sda_generation_result_init(&r,c.mpfr_precision); int rc=sda_generate_for_config(&c,"epsilon-svp-generated",&r); int ok=(rc!=0 || (r.q==r.raw_svp_q && r.q==r.exact_svp_q && r.final_q_from_exact_svp && r.denominator_from_exact_svp && r.global_svp_certified && !r.fixed_q_optimizer_certified && !r.pmf_is_fixed_q_normalized)); for(size_t i=0;ok&&rc==0&&i<r.n;i++)ok=(r.p[i]==r.raw_svp_p[i]); sda_generation_result_clear(&r); return ok?0:3; }
